def modpow(a, n, mod):
    if n == 0:
        return 1
    if n % 2 == 0:
        return modpow(a * a % mod, n // 2, mod)
    return a * modpow(a, n - 1, mod) % mod

def modinv(a, mod):
    return modpow(a, mod - 2, mod)

def concatenate(l, a, b, m):
    # 連結する
    n = 0
    for i in range(l):
        n = (n * 10 + a + b * i) % m
    return n

def main():
    l, a, b, m = map(int, input().split())
    print(concatenate(l, a, b, m))

if __name__ == '__main__':
    main()
